def rotate_matrix(m):
    n = len(m)
    # Reverse the matrix vertically (top to bottom)
    for i in range(n // 2):
        m[i], m[n - 1 - i] = m[n - 1 - i], m[i]
    # Transpose (swap elements across the diagonal)
    for i in range(n):
        for j in range(i + 1, n):
            m[i][j], m[j][i] = m[j][i], m[i][j]
